const express = require('express');
const pg = require('pg');

const app = express();

const connectionString = 'postgres://postgres:password@localhost:5432/database_name';

const client = new pg.Client(connectionString);

client.connect((err) => {
  if (err) throw err;
  console.log('Connected to PostgreSQL database');
});

// CRUD operations for Table 1
app.get('/table1', (req, res) => {
  client.query('SELECT * FROM table1', (err, result) => {
    if (err) throw err;
    res.json(result.rows);
  });
});

// ... CRUD operations for other tables

